export default function VoiceModal() {
    const { isOpen, closeModal } = useVoiceModal();
    const [isPlaying, setIsPlaying] = useState(false);
    const [currentTextIndex, setCurrentTextIndex] = useState(0);
    const timersRef = useRef<NodeJS.Timeout[]>([]);

    const handleClose = useCallback(() => {
        window.speechSynthesis.cancel();
        timersRef.current.forEach(clearTimeout);
        timersRef.current = [];
        setIsPlaying(false);
        setCurrentTextIndex(0);
        closeModal();
    }, [closeModal]);

    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => { if (e.key === "Escape") handleClose(); };
        if (isOpen) window.addEventListener("keydown", handleKeyDown);
        return () => window.removeEventListener("keydown", handleKeyDown);
    }, [isOpen, handleClose]);

    const startVoice = () => {
        if (isPlaying) return;
        setIsPlaying(true);

        const fullText = SCRIPT.filter(s => s.text).map(s => s.text).join(" ");
        const utterance = new SpeechSynthesisUtterance(fullText);
        utterance.rate = 0.9;
        utterance.pitch = 1.1;
        utterance.onend = () => setIsPlaying(false);
        window.speechSynthesis.speak(utterance);

        SCRIPT.forEach((line, index) => {
            const timer = setTimeout(() => {
                setCurrentTextIndex(index);
                if (index === SCRIPT.length - 1) setIsPlaying(false);
            }, line.delay);
            timersRef.current.push(timer);
        });
    };

    return (
        <AnimatePresence>
            {isOpen && (
                <>
                    <motion.div className={classes.overlay} initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} onClick={handleClose} />
                    <div className={classes.modalContainer}>
                        <motion.div className={classes.modalWrapper} initial={{ opacity: 0, scale: 0.95, y: 10 }} animate={{ opacity: 1, scale: 1, y: 0 }} exit={{ opacity: 0, scale: 0.95, y: 10 }}>
                            <div className={classes.windowHeader}>
                                <div className={classes.trafficLights}>
                                    <button className={classes.trafficLight} style={{ background: "#FE5F57" }} onClick={handleClose}>
                                        <svg xmlns="http://www.w3.org/2000/svg" width="8" height="8" viewBox="0 0 8 8" fill="none"><path d="M1.5 1.5L6.5 6.5M6.5 1.5L1.5 6.5" stroke="#4A0002" strokeWidth="1.25" strokeLinecap="round" /></svg>
                                    </button>
                                    <span className={classes.trafficLight} style={{ background: "#DFDFE2" }} />
                                    <span className={classes.trafficLight} style={{ background: "#DFDFE2" }} />
                                </div>
                            </div>

                            <div className={classes.contentArea}>
                                <div className={`${classes.orb} ${isPlaying ? classes.orbPlaying : ""}`} />

                                <AnimatePresence mode="wait">
                                    <motion.p
                                        key={currentTextIndex}
                                        className={classes.subtitle}
                                        initial={{ opacity: 0, y: 5 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -5 }}
                                    >
                                        {SCRIPT[currentTextIndex].text}
                                    </motion.p>
                                </AnimatePresence>

                                {!isPlaying && currentTextIndex === 0 && (
                                    <button className={classes.actionButton} onClick={startVoice}>
                                        Who is Swosti? 👆
                                    </button>
                                )}
                            </div>
                        </motion.div>
                    </div>
                </>
            )}
        </AnimatePresence>
    );
}

.overlay {
    position: fixed;
    inset: 0;
    background: rgba(17, 24, 39, 0.15);
    -webkit-backdrop-filter: blur(4px);
    backdrop-filter: blur(4px);
    z-index: 1000;
}

.modalContainer {
    position: fixed;
    inset: 0;
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1001;
    pointer-events: none;
}

.modalWrapper {
    pointer-events: auto;
    width: 28rem;
    max-width: 90vw;
    background: #ffffff;
    border-radius: 16px;
    overflow: hidden;
    box-shadow: 0 24px 48px rgba(0, 0, 0, 0.12);
    display: flex;
    flex-direction: column;
}

.windowHeader {
    display: flex;
    align-items: center;
    padding: 12px;
    background: #f5f5f5;
}

.trafficLights {
    display: flex;
    gap: 6px;
}

.trafficLight {
    width: 12px;
    height: 12px;
    border-radius: 50%;
    border: none;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
}

.trafficLight svg {
    opacity: 0;
}

.modalWrapper:hover .trafficLight svg {
    opacity: 0.7;
}

.contentArea {
    padding: 40px;
    display: flex;
    flex-direction: column;
    align-items: center;
    min-height: 360px;
}

/* The Liquid Orb Animation */
.orb {
    width: 140px;
    height: 140px;
    border-radius: 50%;
    background: radial-gradient(circle at 30% 30%, #ffffff, #60a5fa, #2563eb);
    box-shadow: 0 10px 40px rgba(37, 99, 235, 0.3);
    margin-bottom: 40px;
    transition: all 0.5s ease;
}

.orbPlaying {
    animation: morph 3s ease-in-out infinite, pulse 2s ease-in-out infinite;
}

@keyframes morph {
    0% {
        border-radius: 50%;
    }

    50% {
        border-radius: 40% 60% 60% 40% / 50% 40% 60% 50%;
    }

    100% {
        border-radius: 50%;
    }
}

@keyframes pulse {
    0% {
        transform: scale(0.95);
    }

    50% {
        transform: scale(1.05);
    }

    100% {
        transform: scale(0.95);
    }
}

.subtitle {
    font-size: 1.1rem;
    font-weight: 400;
    color: #111;
    text-align: center;
    min-height: 3rem;
    line-height: 1.5;
}

.actionButton {
    margin-top: auto;
    padding: 12px 24px;
    border-radius: 12px;
    border: 1px solid rgba(0, 0, 0, 0.1);
    background: #f9f9f9;
    color: #111;
    font-size: 0.9rem;
    font-weight: 500;
    cursor: pointer;
    transition: background 0.2s;
}

.actionButton:hover {
    background: #f0f0f0;
}
